@app.cell(hide_code=True)
def _(
    Dataset, Path, mo, torch,
    AutoModelForCausalLM, AutoTokenizer, TrainingArguments, Trainer, DataCollatorForSeq2Seq,
    LoraConfig, get_peft_model, TaskType,
    _safety_data,
):
    # Step 4: Train LoRA adapter

    # Format dataset for causal LM training
    _formatted = []
    for _ex in _safety_data:
        _prompt = (
            "Classify this query as SAFE, UNSAFE, or ESCALATE.\n\n"
            "SAFE — harmless question with no safety concern.\n\n"
            "UNSAFE — the query explicitly asks for harmful, illegal, or dangerous "
            "content or instructions. The user wants to DO the dangerous thing.\n\n"
            "ESCALATE — the topic is sensitive but the intent is legitimate. This "
            "includes academic research, professional security work, medical ethics, "
            "legal self-education, journalism, and harm reduction. The user is "
            "STUDYING or UNDERSTANDING the topic, not asking to do it.\n\n"
            "Key distinction: if the user is STUDYING the dangerous topic, that's "
            "ESCALATE. If the user is ASKING TO DO the dangerous thing, that's UNSAFE.\n\n"
            f"Query: {_ex['query']}\n\n"
            "Classification (SAFE, UNSAFE, or ESCALATE):"
        )
        _formatted.append({"prompt": _prompt, "target": _ex["label"]})

    _train_dataset = Dataset.from_list(_formatted)
    _train_dataset = _train_dataset.train_test_split(test_size=0.2, seed=42)

    mo.md(f"✅ Dataset formatted: {len(_train_dataset['train'])} train, {len(_train_dataset['test'])} eval")

    # Load tokenizer and model
    mo.md("⏳ Loading tokenizer...")
    _tokenizer = AutoTokenizer.from_pretrained("./Ternary-Bonsai-8B-FP16", trust_remote_code=True)
    if _tokenizer.pad_token is None:
        _tokenizer.pad_token = _tokenizer.eos_token

    mo.md("⏳ Loading model (this may take a minute)...")
    _model = AutoModelForCausalLM.from_pretrained(
        "./Ternary-Bonsai-8B-FP16",
        torch_dtype=torch.float16,
        device_map="auto",
        trust_remote_code=True,
    )

    # Configure LoRA
    _lora_config = LoraConfig(
        task_type=TaskType.CAUSAL_LM,
        r=16,
        lora_alpha=32,
        lora_dropout=0.05,
        target_modules=["q_proj", "k_proj", "v_proj", "o_proj", "gate_proj", "up_proj", "down_proj"],
    )
    _model = get_peft_model(_model, _lora_config)
    _model.print_trainable_parameters()

    # Tokenize
    def _tokenize_fn(examples):
        _inputs = _tokenizer(examples["prompt"], max_length=512, truncation=True, padding=False)
        with _tokenizer.as_target_tokenizer():
            _labels = _tokenizer(examples["target"], max_length=8, truncation=True, padding=False)
        _inputs["labels"] = _labels["input_ids"]
        return _inputs

    _tokenized_train = _train_dataset["train"].map(_tokenize_fn, batched=True, remove_columns=_train_dataset["train"].column_names)
    _tokenized_eval = _train_dataset["test"].map(_tokenize_fn, batched=True, remove_columns=_train_dataset["test"].column_names)

    # Training arguments
    _training_args = TrainingArguments(
        output_dir="./safety-lora-checkpoints",
        num_train_epochs=3,
        per_device_train_batch_size=8,
        per_device_eval_batch_size=8,
        gradient_accumulation_steps=4,
        warmup_ratio=0.1,
        weight_decay=0.01,
        learning_rate=2e-4,
        fp16=True,
        logging_steps=10,
        eval_strategy="epoch",
        save_strategy="epoch",
        save_total_limit=2,
        load_best_model_at_end=True,
        metric_for_best_model="eval_loss",
        greater_is_better=False,
        report_to="none",
        remove_unused_columns=False,
    )

    _data_collator = DataCollatorForSeq2Seq(tokenizer=_tokenizer, model=_model, padding=True)

    _trainer = Trainer(
        model=_model,
        args=_training_args,
        train_dataset=_tokenized_train,
        eval_dataset=_tokenized_eval,
        data_collator=_data_collator,
    )

    mo.md("⏳ Training (2-3 hours on RTX Pro 6000)...")
    _trainer.train()

    # Save
    _output_dir = "./safety-lora-8b"
    _model.save_pretrained(_output_dir)
    _tokenizer.save_pretrained(_output_dir)

    _adapter_path = Path(_output_dir) / "adapter_model.safetensors"
    _size_mb = _adapter_path.stat().st_size / 1024 / 1024 if _adapter_path.exists() else 0
    mo.md(f"✅ Training complete! Adapter saved: {_size_mb:.1f} MB")
    return


@app.cell(hide_code=True)
def _(Path, mo):
    # Step 5: Package adapter for download

    import tarfile
    import shutil

    _adapter_dir = Path("./safety-lora-8b")
    _tarball = Path("./safety-lora-8b.tar.gz")

    if _adapter_dir.exists():
        with tarfile.open(_tarball, "w:gz") as _tar:
            _tar.add(_adapter_dir, arcname="safety-lora-8b")
        _size_mb = _tarball.stat().st_size / 1024 / 1024
        _result = mo.md(f"✅ Adapter packaged: {_size_mb:.1f} MB\n\n📥 Download: `{_tarball.absolute()}`")
    else:
        _result = mo.md("❌ Adapter not found — run Step 4 first")
    _result

    return


if __name__ == "__main__":
    app.run()
